    def _sanitize_index_name(self, index_name: str) -> str:
        if not re.match(r'^[a-z0-9_\-\.]+$', index_name):
            raise ValueError(
                "Index name must contain only lowercase letters, numbers, hyphens, underscores, and dots"
            )
        
