class LoggingService:
    def __init__(self, es_client: SecureElasticsearchClient, index_prefix: str = 'logs'):
        self.es_client = es_client
        self.index_prefix = index_prefix
        self._create_log_index_template()
    
    def _create_log_index_template(self):
        index_name = f"{self.index_prefix}-{datetime.utcnow().strftime('%Y.%m.%d')}"
        
        mappings = {
            'properties': {
                'timestamp': {'type': 'date'},
                'level': {'type': 'keyword'},
                'message': {'type': 'text'},
                'service': {'type': 'keyword'},
                'host': {'type': 'keyword'},
                'user': {'type': 'keyword'},
                'metadata': {'type': 'object'},
                'indexed_at': {'type': 'date'}
            }
        }
        
        settings = {
            'number_of_shards': 1,
            'number_of_replicas': 1
        }
        
        try:
            self.es_client.create_index(index_name, mappings, settings)
        except Exception:
            pass
    
    def log(
        self,
        level: str,
        message: str,
        service: str,
        host: Optional[str] = None,
        user: Optional[str] = None,
        metadata: Optional[Dict] = None
    ) -> Dict:
        index_name = f"{self.index_prefix}-{datetime.utcnow().strftime('%Y.%m.%d')}"
        
        log_entry = {
            'timestamp': datetime.utcnow().isoformat(),
            'level': level.upper(),
            'message': message,
            'service': service
        }
        
        if host:
            log_entry['host'] = host
        if user:
            log_entry['user'] = user
        if metadata:
            log_entry['metadata'] = metadata
        
        return self.es_client.index_document(index_name, log_entry)
    
    def search_logs(
        self,
        start_date: Optional[datetime] = None,
        end_date: Optional[datetime] = None,
        level: Optional[str] = None,
        service: Optional[str] = None,
        search_text: Optional[str] = None,
        size: int = 100
    ) -> Dict:
        index_pattern = f"{self.index_prefix}-*"
        
        must_clauses = []
        
        if start_date or end_date:
            range_query = {'timestamp': {}}
            if start_date:
                range_query['timestamp']['gte'] = start_date.isoformat()
            if end_date:
                range_query['timestamp']['lte'] = end_date.isoformat()
            must_clauses.append({'range': range_query})
        
        if level:
            must_clauses.append({'term': {'level': level.upper()}})
        
        if service:
            must_clauses.append({'term': {'service': service}})
        
        if search_text:
            must_clauses.append({
                'multi_match': {
                    'query': search_text,
                    'fields': ['message', 'service', 'host', 'user']
                }
            })
        
        query = {
            'bool': {
                'must': must_clauses if must_clauses else [{'match_all': {}}]
            }
        }
        
        sort = [{'timestamp': {'order': 'desc'}}]
        
        return self.es_client.search(index_pattern, query, size=size, sort=sort)
    
    def aggregate_logs_by_level(
        self,
        start_date: Optional[datetime] = None,
        end_date: Optional[datetime] = None
    ) -> Dict:
        index_pattern = f"{self.index_prefix}-*"
        
