class DocumentSearchService:
    def __init__(self, es_client: SecureElasticsearchClient, index_name: str = 'documents'):
        self.es_client = es_client
        self.index_name = index_name
        self._create_document_index()
    
    def _create_document_index(self):
        mappings = {
            'properties': {
                'title': {
                    'type': 'text',
                    'fields': {
                        'keyword': {'type': 'keyword'}
                    }
                },
                'content': {'type': 'text'},
                'author': {'type': 'keyword'},
                'tags': {'type': 'keyword'},
                'category': {'type': 'keyword'},
                'created_at': {'type': 'date'},
                'updated_at': {'type': 'date'},
                'indexed_at': {'type': 'date'}
            }
        }
        
        settings = {
            'number_of_shards': 2,
            'number_of_replicas': 1,
            'analysis': {
                'analyzer': {
                    'custom_analyzer': {
                        'type': 'custom',
                        'tokenizer': 'standard',
                        'filter': ['lowercase', 'stop', 'snowball']
                    }
                }
            }
        }
        
        try:
            self.es_client.create_index(self.index_name, mappings, settings)
        except Exception:
            pass
    
    def add_document(
        self,
        title: str,
        content: str,
        author: str,
        tags: Optional[List[str]] = None,
        category: Optional[str] = None,
        doc_id: Optional[str] = None
    ) -> Dict:
        document = {
            'title': title,
            'content': content,
            'author': author,
            'created_at': datetime.utcnow().isoformat(),
            'updated_at': datetime.utcnow().isoformat()
        }
        
        if tags:
            document['tags'] = tags
        if category:
            document['category'] = category
        
        return self.es_client.index_document(self.index_name, document, doc_id)
    
    def search_documents(
        self,
        search_text: str,
        fields: Optional[List[str]] = None,
        filters: Optional[Dict] = None,
        size: int = 10,
        from_: int = 0
    ) -> Dict:
        if fields is None:
            fields = ['title^2', 'content', 'tags']
        
        must_clauses = [
            {
                'multi_match': {
                    'query': search_text,
                    'fields': fields,
                    'type': 'best_fields',
                    'fuzziness': 'AUTO'
                }
            }
        ]
        
        if filters:
            for field, value in filters.items():
                if isinstance(value, list):
                    must_clauses.append({'terms': {field: value}})
                else:
                    must_clauses.append({'term': {field: value}})
        
        query = {
            'bool': {
                'must': must_clauses
            }
        }
        
        return self.es_client.search(self.index_name, query, size, from_)
    
    def search_by_category(self, category: str, size: int = 10) -> Dict:
        query = {
            'term': {
                'category': category
            }
        }
        
        return self.es_client.search(self.index_name, query, size)
    
    def search_by_tags(self, tags: List[str], size: int = 10) -> Dict:
        query = {
            'terms': {
                'tags': tags
            }
        }
        
        return self.es_client.search(self.index_name, query, size)
    
    def search_by_author(self, author: str, size: int = 10) -> Dict:
        query = {
            'term': {
                'author': author
            }
        }
        
        return self.es_client.search(self.index_name, query, size)


